/**
 * MedX motion theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Duration and easing curves for transitions.
 */
const MOTION_TOKENS = Object.freeze({
  primary: { value: "theme-motion-primary", scope: "theme" },
  secondary: { value: "theme-motion-secondary", scope: "theme" },
  muted: { value: "theme-motion-muted", scope: "theme" },
  accent: { value: "theme-motion-accent", scope: "theme" },
  surface: { value: "theme-motion-surface", scope: "theme" },
});

const MOTION_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const MOTION_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const motionRegistry = new Map();
const MOTION_listeners = new Set();
let MOTION_seq = 0;

function createMotionId(prefix = "medx-theme-motion") {
  MOTION_seq += 1;
  return `${prefix}-${MOTION_seq}`;
}

function registerMotion(config = {}) {
  const entryId = config.id ?? createMotionId();
  const preset = MOTION_PRESETS[config.preset ?? "default"] ?? MOTION_PRESETS.default;
  const token = MOTION_TOKENS[config.token ?? preset.token] ?? MOTION_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: MOTION_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  motionRegistry.set(entryId, entry);
  notifyMotionListeners("register", entry);
  return entry;
}

function updateMotion(id, patch = {}) {
  const entry = motionRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyMotionListeners("update", entry);
  return entry;
}

function resolveMotion(id) {
  const entry = motionRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listMotionEntries(filter = {}) {
  let items = Array.from(motionRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onMotionEvent(listener) {
  MOTION_listeners.add(listener);
  return () => MOTION_listeners.delete(listener);
}

function notifyMotionListeners(type, entry) {
  for (const listener of MOTION_listeners) {
    try {
      listener({ type, entry, registrySize: motionRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:motion] listener error", err.message);
    }
  }
}

function getMotionMetrics() {
  const items = listMotionEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(MOTION_TOKENS).length,
    presets: Object.keys(MOTION_PRESETS).length,
  };
}

async function runMedxMotion() {
  console.log("[medx:ui:theme:motion] runtime initialized");
  console.log(`[medx:ui:theme:motion] tokens=${Object.keys(MOTION_TOKENS).length} presets=${Object.keys(MOTION_PRESETS).length}`);

  const events = [];
  onMotionEvent((e) => events.push(e.type));

  const domains = Object.keys(MOTION_SUPPLY_CHAIN);
  const presets = Object.keys(MOTION_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerMotion({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/motion" },
    });
  }

  const first = listMotionEntries()[0];
  if (first) updateMotion(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getMotionMetrics();
  const resolved = first ? resolveMotion(first.id) : null;

  console.log(`[medx:ui:theme:motion] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:motion] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:motion] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:motion] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:motion] bootstrap complete");
}

module.exports = runMedxMotion;
